#include <bits/stdc++.h>
using namespace std;
int a[110];
int main(){
    int n;
    cin >> n;
    for(int i=1; i<=n; i++){
        cin >> a[i];
    }
    for(int i=1; i<n; i++){
        int mi_id = i;
        for(int j=i+1; j<=n; j++){
            if(a[mi_id] > a[j]){
                mi_id = j;
            }
        }
        swap(a[mi_id], a[i]);
    }
    for(int i=1; i<=n; i++){
        cout << a[i] << " ";
    }
    return 0;
}
